export default function ClubMembers({ members }) {
    return (
        <div className="card">
            <h3>Members</h3>
            <ul>
                {members.map(m => (
                    <li key={m.id}>
                        User #{m.userId} — {m.role}
                    </li>
                ))}
            </ul>
        </div>
    );
}
